import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiUploadCloud, FiCheckCircle } from 'react-icons/fi';
import { uploadModelAnswer, evaluateAnswer, getAllStudents, createStudent } from '../services/api';
import './Evaluate.css';

const Evaluate = ({ setLoading }) => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [modelAnswerText, setModelAnswerText] = useState('');
  const [studentFile, setStudentFile] = useState(null);
  const [maxMarks, setMaxMarks] = useState('');
  const [question, setQuestion] = useState('');

  const [students, setStudents] = useState([]);
  const [selectedStudent, setSelectedStudent] = useState('');
  const [error, setError] = useState('');
  const [results, setResults] = useState(null);

  const [showNewStudent, setShowNewStudent] = useState(false);
  const [newStudent, setNewStudent] = useState({
    name: '',
    email: '',
    rollNumber: '',
    class: ''
  });

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    try {
      const res = await getAllStudents();
      setStudents(res.students || []);
    } catch (err) {
      console.error('Error loading students:', err);
    }
  };

  const handleModelAnswerUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setError('');
    setLoading(true, 'Extracting model answer...');

    try {
      const response = await uploadModelAnswer(file);
      setModelAnswerText(response.model_answer);
      setStep(2);
    } catch (err) {
      setError(err.response?.data?.error || err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleAddStudent = async () => {
    if (!newStudent.name || !newStudent.email) {
      setError('Name and email are required');
      return;
    }

    try {
      const response = await createStudent(
        newStudent.name,
        newStudent.email,
        newStudent.rollNumber,
        newStudent.class
      );

      setStudents([...students, response.student]);
      setSelectedStudent(response.student._id);

      setShowNewStudent(false);
      setNewStudent({ name: '', email: '', rollNumber: '', class: '' });

    } catch (err) {
      setError(err.response?.data?.error || err.message);
    }
  };

  const handleEvaluate = async () => {
    if (!studentFile) return setError('Please upload a student answer file');
    if (!maxMarks) return setError('Please enter maximum marks');
    if (!selectedStudent) return setError('Please select a student');
    if (!modelAnswerText) return setError('Please enter model answer');

    setError('');
    setLoading(true, 'Evaluating answer...');

    try {
      const formData = new FormData();
      formData.append('student_file', studentFile);
      formData.append('model_answer', modelAnswerText);
      formData.append('max_marks', maxMarks);
      formData.append('question', question);
      formData.append('student_id', selectedStudent);

      const response = await evaluateAnswer(formData);
      const evaluationData = response.evaluation || response;
      evaluationData.max_marks = maxMarks;

      setResults(evaluationData);
      navigate('/results/new', { state: { evaluation: evaluationData } });

    } catch (err) {
      setError(err.response?.data?.error || err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="evaluate">
      <div className="evaluate-container">
        <h1 className="page-title">Evaluate Answer</h1>

        {error && <div className="error-alert">{error}</div>}

        {/* STEP 1 */}
        {step === 1 && (
          <div className="step-content">
            <h2>Upload Model Answer</h2>

            <div className="upload-area">
              <input
                type="file"
                id="modelAnswerFile"
                accept=".pdf"
                onChange={handleModelAnswerUpload}
                className="file-input"
              />
              <label htmlFor="modelAnswerFile" className="upload-label">
                <FiUploadCloud size={48} />
                <p className="upload-text">Upload Model Answer</p>
              </label>
            </div>

            <textarea
              value={modelAnswerText}
              onChange={(e) => setModelAnswerText(e.target.value)}
              className="textarea"
              rows="6"
              placeholder="Or paste model answer..."
            />

            <button
              className="btn btn-primary btn-lg"
              onClick={() => setStep(2)}
              disabled={!modelAnswerText}
            >
              Next →
            </button>
          </div>
        )}

        {/* STEP 2 */}
        {step === 2 && (
          <div className="step-content">
            <h2>Student Answer & Details</h2>

            {/* ✅ FIXED STUDENT SECTION */}
            <div className="form-section">
              <h3>Student</h3>

              <div className="form-group">
                <label>Select Student *</label>
                <div className="select-group">
                  <select
                    value={selectedStudent}
                    onChange={(e) => setSelectedStudent(e.target.value)}
                    className="form-select"
                  >
                    <option value="">Choose a student...</option>
                    {students.map(student => (
                      <option key={student._id} value={student._id}>
                        {student.name} ({student.rollNumber})
                      </option>
                    ))}
                  </select>

                  <button
                    className="btn-icon"
                    onClick={() => setShowNewStudent(!showNewStudent)}
                  >
                    +
                  </button>
                </div>
              </div>

              {showNewStudent && (
                <div className="add-form">
                  <input
                    type="text"
                    placeholder="Student name"
                    value={newStudent.name}
                    onChange={(e) =>
                      setNewStudent({ ...newStudent, name: e.target.value })
                    }
                    className="form-input"
                  />

                  <input
                    type="email"
                    placeholder="Email"
                    value={newStudent.email}
                    onChange={(e) =>
                      setNewStudent({ ...newStudent, email: e.target.value })
                    }
                    className="form-input"
                  />

                  <input
                    type="text"
                    placeholder="Roll number"
                    value={newStudent.rollNumber}
                    onChange={(e) =>
                      setNewStudent({ ...newStudent, rollNumber: e.target.value })
                    }
                    className="form-input"
                  />

                  <input
                    type="text"
                    placeholder="Class"
                    value={newStudent.class}
                    onChange={(e) =>
                      setNewStudent({ ...newStudent, class: e.target.value })
                    }
                    className="form-input"
                  />

                  <button
                    className="btn btn-sm btn-primary"
                    onClick={handleAddStudent}
                  >
                    Add Student
                  </button>
                </div>
              )}
            </div>

            {/* Upload */}
            <div className="form-section">
              <h3>Student Answer</h3>

              <input
                type="file"
                accept=".pdf,.png,.jpg,.jpeg"
                onChange={(e) => setStudentFile(e.target.files[0])}
              />

              {studentFile && <p>{studentFile.name}</p>}
            </div>

            {/* Details */}
            <div className="form-section">
              <input
                type="number"
                placeholder="Max Marks"
                value={maxMarks}
                onChange={(e) => setMaxMarks(e.target.value)}
                className="form-input"
              />
            </div>

            <button className="btn btn-primary" onClick={handleEvaluate}>
              Evaluate
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Evaluate;
